def prime_factors(n):
    factors, d = [], 2
    while d * d <= n:
        e = 0
        while n % d == 0:
            n //= d; e += 1
        if e: factors.append((d, e))
        d += 1
    if n > 1: factors.append((n, 1))
    return factors

```python
def prime_factorization(n: int) -> list[tuple[int, int]]:
    if n < 1:
        raise ValueError('n must be a positive integer')

    factors = []
    divisor = 2
    while divisor * divisor <= n:
        exponent = 0
        while n % divisor == 0:
            n //= divisor
            exponent += 1
        if exponent:
            factors.append((divisor, exponent))
        divisor = 3 if divisor == 2 else divisor + 2

    if n > 1:
        factors.append((n, 1))
    return factors
```
For example, `prime_factorization(360)` returns `[(2, 3), (3, 2), (5, 1)]`.

