import heapq

def dijkstra(graph, source):
    distances = {node: float('inf') for node in graph}
    distances[source] = 0
    heap = [(0, source)]

    while heap:
        current_distance, node = heapq.heappop(heap)
        if current_distance != distances[node]:
            continue

        for neighbor, weight in graph[node].items():
            if weight < 0:
                raise ValueError('Dijkstra requires non-negative edge weights')
            candidate = current_distance + weight
            if candidate < distances[neighbor]:
                distances[neighbor] = candidate
                heapq.heappush(heap, (candidate, neighbor))

    return distances
```
With a binary heap, the runtime is typically `O((V + E) log V)`.

def has_cycle(g):
    WHITE, GRAY, BLACK = 0, 1, 2
    color = {u: WHITE for u in g}
    def dfs(u):
        color[u] = GRAY
        for v in g.get(u, []):
            if color.get(v, WHITE) == GRAY: return True
            if color.get(v, WHITE) == WHITE and dfs(v): return True
        color[u] = BLACK
        return False
    return any(dfs(u) for u in g if color[u] == WHITE)

```python
def has_directed_cycle(graph):
    UNVISITED, VISITING, DONE = 0, 1, 2
    state = {node: UNVISITED for node in graph}

    def dfs(node):
        state[node] = VISITING
        for neighbor in graph.get(node, []):
            neighbor_state = state.get(neighbor, UNVISITED)
            if neighbor_state == VISITING:
                return True
            if neighbor_state == UNVISITED:
                state.setdefault(neighbor, UNVISITED)
                if dfs(neighbor):
                    return True
        state[node] = DONE
        return False

    return any(state[node] == UNVISITED and dfs(node) for node in list(state))
```
A back edge to a currently visiting node proves a directed cycle exists.

def lcs(a, b):
    m, n = len(a), len(b)
    dp = [[''] * (n+1) for _ in range(m+1)]
    for i in range(m):
        for j in range(n):
            if a[i] == b[j]: dp[i+1][j+1] = dp[i][j] + a[i]
            else: dp[i+1][j+1] = max(dp[i+1][j], dp[i][j+1], key=len)
    return dp[m][n]

```python
def lcs(a: str, b: str) -> str:
    m, n = len(a), len(b)
    dp = [['' for _ in range(n + 1)] for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + a[i - 1]
            else:
                left = dp[i - 1][j]
                right = dp[i][j - 1]
                dp[i][j] = left if len(left) >= len(right) else right

    return dp[m][n]
```
This returns one longest common subsequence, not necessarily the only one. It is straightforward but memory-heavy for very long strings.

