from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        if capacity <= 0:
            raise ValueError('capacity must be positive')
        self.capacity = capacity
        self.data = OrderedDict()

    def get(self, key):
        if key not in self.data:
            return -1
        self.data.move_to_end(key)
        return self.data[key]

    def put(self, key, value):
        if key in self.data:
            self.data.move_to_end(key)
        self.data[key] = value
        if len(self.data) > self.capacity:
            self.data.popitem(last=False)
```
`OrderedDict` maintains recency order, giving average `O(1)` lookup, update, and eviction.

from collections import defaultdict, deque
def topo(graph):
    indeg = defaultdict(int)
    for u in graph:
        for v in graph[u]: indeg[v] += 1
        indeg.setdefault(u, indeg[u])
    q = deque([u for u in indeg if indeg[u] == 0])
    out = []
    while q:
        u = q.popleft(); out.append(u)
        for v in graph.get(u, []):
            indeg[v] -= 1
            if indeg[v] == 0: q.append(v)
    if len(out) != len(indeg): raise ValueError('cycle')
    return out

