import random

def kth_smallest(values, k):
    if not 0 <= k < len(values):
        raise IndexError("k out of range")

    items = list(values)

    def select(left, right, k):
        while True:
            if left == right:
                return items[left]

            pivot_index = random.randint(left, right)
            pivot_index = partition(left, right, pivot_index)

            if k == pivot_index:
                return items[k]
            if k < pivot_index:
                right = pivot_index - 1
            else:
                left = pivot_index + 1

    def partition(left, right, pivot_index):
        pivot_value = items[pivot_index]
        items[pivot_index], items[right] = items[right], items[pivot_index]
        store = left

        for i in range(left, right):
            if items[i] < pivot_value:
                items[store], items[i] = items[i], items[store]
                store += 1

        items[right], items[store] = items[store], items[right]
        return store

    return select(0, len(items) - 1, k)
```
Here `k` is zero-based. Expected runtime is `O(n)` with randomized pivots, though worst case remains `O(n²)`.

