def is_perfect_square(n: int) -> bool:
    if n < 0:
        return False

    lo, hi = 0, n
    while lo <= hi:
        mid = (lo + hi) // 2
        square = mid * mid

        if square == n:
            return True
        if square < n:
            lo = mid + 1
        else:
            hi = mid - 1

    return False
```
This avoids floating-point `sqrt` precision issues by using integer binary search.

